mapper.select:
(SELECT t1.id, t1.name, t1.disk_id, "1" AS is_file, t1.node, t1.parent_node, null as size, null as folder_id, null as hash_id, null as status, t1.create_time, t1.update_time FROM xc_folder as t1
LEFT JOIN xc_share_folder_file as t2 ON t1.id=t2.folder_id
1=1
and t1.disk_id = #{obj.diskId}
and t1.name LIKE CONCAT('%', #{obj.name}, '%')
and t1.parent_node = #{obj.parentNode}
and t2.share_id =#{obj.shareId}
and t2.is_root =#{obj.isRoot}
UNION ALL SELECT t3.id, t3.name, t3.disk_id, "0" as is_file, null as node, null as parent_node, t3.size, t3.folder_id, t3.hash_id, t3.status, t3.create_time, t3.update_time FROM xc_file as t3
LEFT JOIN xc_share_folder_file as t4 ON t3.id=t4.file_id
t3.status='0'
and t3.disk_id = #{obj.diskId}
and t3.name LIKE CONCAT('%', #{obj.name}, '%')
and t3.folder_id = #{obj.folderId}
and t4.share_id =#{obj.shareId}
and t4.is_root =#{obj.isRoot}
) ${ew.customSqlSegment}
